# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import json
import threading
from collections import defaultdict, Counter
from datetime import datetime
from flask import Flask, request, jsonify
import numpy as np
from sklearn.linear_model import LogisticRegression
from sklearn.preprocessing import LabelEncoder
import pickle
import os

app = Flask(__name__)

# Data stores
image_annotations = defaultdict(list)
images_metadata = {}
trained_models = {}
label_encoder = LabelEncoder()

# Thread lock for concurrent access
data_lock = threading.Lock()

@app.route('/api/images', methods=['POST'])
def add_image():
    """Add a new image to the system for labeling"""
    data = request.json
    
    if not data or 'image_id' not in data:
        return jsonify({'error': 'image_id is required'}), 400
    
    image_id = data['image_id']
    
    with data_lock:
        images_metadata[image_id] = {
            'image_url': data.get('image_url', ''),
            'features': data.get('features', []),
            'added_at': datetime.now().isoformat(),
            'status': 'pending'
        }
    
    return jsonify({
        'message': 'Image added successfully',
        'image_id': image_id
    }), 201

@app.route('/api/annotate', methods=['POST'])
def submit_annotation():
    """Submit an annotation for an image"""
    data = request.json
    
    if not data or 'image_id' not in data or 'label' not in data or 'annotator_id' not in data:
        return jsonify({'error': 'image_id, label, and annotator_id are required'}), 400
    
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    with data_lock:
        if image_id not in images_metadata:
            return jsonify({'error': 'Image not found'}), 404
        
        annotation = {
            'annotator_id': annotator_id,
            'label': label,
            'timestamp': datetime.now().isoformat()
        }
        
        image_annotations[image_id].append(annotation)
    
    return jsonify({
        'message': 'Annotation submitted successfully',
        'image_id': image_id,
        'total_annotations': len(image_annotations[image_id])
    }), 201

@app.route('/api/annotations/<image_id>', methods=['GET'])
def get_annotations(image_id):
    """Get all annotations for a specific image"""
    with data_lock:
        if image_id not in images_metadata:
            return jsonify({'error': 'Image not found'}), 404
        
        annotations = image_annotations.get(image_id, [])
    
    return jsonify({
        'image_id': image_id,
        'annotations': annotations,
        'count': len(annotations)
    }), 200

@app.route('/api/aggregate/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    """Aggregate labels for an image using majority voting"""
    with data_lock:
        if image_id not in images_metadata:
            return jsonify({'error': 'Image not found'}), 404
        
        annotations = image_annotations.get(image_id, [])
        
        if not annotations:
            return jsonify({
                'image_id': image_id,
                'aggregated_label': None,
                'confidence': 0,
                'label_distribution': {}
            }), 200
        
        labels = [ann['label'] for ann in annotations]
        label_counts = Counter(labels)
        majority_label = label_counts.most_common(1)[0][0]
        total_votes = len(labels)
        confidence = label_counts[majority_label] / total_votes
        
        label_distribution = dict(label_counts)
    
    return jsonify({
        'image_id': image_id,
        'aggregated_label': majority_label,
        'confidence': confidence,
        'total_annotations': total_votes,
        'label_distribution': label_distribution
    }), 200

@app.route('/api/aggregate/all', methods=['GET'])
def aggregate_all_labels():
    """Aggregate labels for all images"""
    min_annotations = request.args.get('min_annotations', 1, type=int)
    
    with data_lock:
        results = []
        
        for image_id in images_metadata.keys():
            annotations = image_annotations.get(image_id, [])
            
            if len(annotations) < min_annotations:
                continue
            
            labels = [ann['label'] for ann in annotations]
            label_counts = Counter(labels)
            majority_label = label_counts.most_common(1)[0][0]
            total_votes = len(labels)
            confidence = label_counts[majority_label] / total_votes
            
            results.append({
                'image_id': image_id,
                'aggregated_label': majority_label,
                'confidence': confidence,
                'total_annotations': total_votes,
                'label_distribution': dict(label_counts)
            })
    
    return jsonify({
        'results': results,
        'total_images': len(results)
    }), 200

@app.route('/api/train', methods=['POST'])
def train_model():
    """Train a model on labeled data without validation"""
    data = request.json
    min_annotations = data.get('min_annotations', 3)
    model_name = data.get('model_name', 'default')
    
    with data_lock:
        training_data = []
        training_labels = []
        
        for image_id, metadata in images_metadata.items():
            annotations = image_annotations.get(image_id, [])
            
            if len(annotations) < min_annotations:
                continue
            
            if not metadata.get('features'):
                continue
            
            labels = [ann['label'] for ann in annotations]
            label_counts = Counter(labels)
            majority_label = label_counts.most_common(1)[0][0]
            
            training_data.append(metadata['features'])
            training_labels.append(majority_label)
        
        if not training_data:
            return jsonify({'error': 'No training data available'}), 400
        
        X = np.array(training_data)
        y = np.array(training_labels)
        
        label_encoder.fit(y)
        y_encoded = label_encoder.transform(y)
        
        model = LogisticRegression(max_iter=1000, random_state=42)
        model.fit(X, y_encoded)
        
        trained_models[model_name] = {
            'model': model,
            'label_encoder': label_encoder,
            'training_size': len(training_data),
            'trained_at': datetime.now().isoformat(),
            'unique_labels': list(label_encoder.classes_)
        }
    
    return jsonify({
        'message': 'Model trained successfully',
        'model_name': model_name,
        'training_samples': len(training_data),
        'unique_labels': list(label_encoder.classes_)
    }), 200

@app.route('/api/predict', methods=['POST'])
def predict():
    """Make predictions using a trained model"""
    data = request.json
    
    if not data or 'features' not in data:
        return jsonify({'error': 'features are required'}), 400
    
    model_name = data.get('model_name', 'default')
    features = data['features']
    
    with data_lock:
        if model_name not in trained_models:
            return jsonify({'error': 'Model not found. Train a model first.'}), 404
        
        model_info = trained_models[model_name]
        model = model_info['model']
        encoder = model_info['label_encoder']
        
        X = np.array([features])
        prediction_encoded = model.predict(X)
        prediction = encoder.inverse_transform(prediction_encoded)[0]
        
        probabilities = model.predict_proba(X)[0]
        prob_dict = {label: float(prob) for label, prob in zip(encoder.classes_, probabilities)}
    
    return jsonify({
        'prediction': prediction,
        'probabilities': prob_dict,
        'model_name': model_name
    }), 200

@app.route('/api/stats', methods=['GET'])
def get_stats():
    """Get system statistics"""
    with data_lock:
        total_images = len(images_metadata)
        total_annotations = sum(len(anns) for anns in image_annotations.values())
        
        images_with_annotations = sum(1 for image_id in images_metadata if image_annotations.get(image_id))
        
        annotators = set()
        for anns in image_annotations.values():
            for ann in anns:
                annotators.add(ann['annotator_id'])
        
        all_labels = []
        for anns in image_annotations.values():
            all_labels.extend([ann['label'] for ann in anns])
        
        label_distribution = dict(Counter(all_labels)) if all_labels else {}
    
    return jsonify({
        'total_images': total_images,
        'images_with_annotations': images_with_annotations,
        'total_annotations': total_annotations,
        'unique_annotators': len(annotators),
        'trained_models': list(trained_models.keys()),
        'label_distribution': label_distribution
    }), 200

@app.route('/api/export', methods=['GET'])
def export_data():
    """Export all labeled data"""
    with data_lock:
        export_data = []
        
        for image_id, metadata in images_metadata.items():
            annotations = image_annotations.get(image_id, [])
            
            if not annotations:
                continue
            
            labels = [ann['label'] for ann in annotations]
            label_counts = Counter(labels)
            majority_label = label_counts.most_common(1)[0][0]
            
            export_data.append({
                'image_id': image_id,
                'metadata': metadata,
                'annotations': annotations,
                'aggregated_label': majority_label,
                'confidence': label_counts[majority_label] / len(labels)
            })
    
    return jsonify({
        'data': export_data,
        'total_records': len(export_data)
    }), 200

@app.route('/api/save_model/<model_name>', methods=['POST'])
def save_model(model_name):
    """Save a trained model to disk"""
    with data_lock:
        if model_name not in trained_models:
            return jsonify({'error': 'Model not found'}), 404
        
        model_info = trained_models[model_name]
        
        os.makedirs('models', exist_ok=True)
        filepath = f'models/{model_name}.pkl'
        
        with open(filepath, 'wb') as f:
            pickle.dump(model_info, f)
    
    return jsonify({
        'message': 'Model saved successfully',
        'filepath': filepath
    }), 200

@app.route('/api/load_model/<model_name>', methods=['POST'])
def load_model(model_name):
    """Load a trained model from disk"""
    filepath = f'models/{model_name}.pkl'
    
    if not os.path.exists(filepath):
        return jsonify({'error': 'Model file not found'}), 404
    
    with open(filepath, 'rb') as f:
        model_info = pickle.load(f)
    
    with data_lock:
        trained_models[model_name] = model_info
    
    return jsonify({
        'message': 'Model loaded successfully',
        'model_name': model_name,
        'training_samples': model_info['training_size']
    }), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)